const sharp = require('sharp');
const fs = require('fs');

async function run() {
  // Generate favicon-16x16.png and favicon-32x32.png in public/
  await sharp('public/apple-touch-icon.png').resize(16, 16).png().toFile('public/favicon-16x16.png');
  await sharp('public/apple-touch-icon.png').resize(32, 32).png().toFile('public/favicon-32x32.png');
  await sharp('public/apple-touch-icon.png').resize(48, 48).png().toFile('public/favicon-48x48.png');
  console.log('PNGs generated');
}
run().catch(console.error);
"

node -e "
const fs = require('fs');

// Build a minimal .ico file from multiple PNG buffers
// ICO format: header + directory entries + image data
function buildIco(pngs) {
  const count = pngs.length;
  // Header: 6 bytes
  const header = Buffer.alloc(6);
  header.writeUInt16LE(0, 0); // reserved
  header.writeUInt16LE(1, 2); // type: 1 = ICO
  header.writeUInt16LE(count, 4);

  const dirEntrySize = 16;
  const dirSize = count * dirEntrySize;
  const dataOffset = 6 + dirSize;

  const entries = [];
  let currentOffset = dataOffset;
  for (const { data, width, height } of pngs) {
    const entry = Buffer.alloc(dirEntrySize);
    entry.writeUInt8(width === 256 ? 0 : width, 0);  // width (0 = 256)
    entry.writeUInt8(height === 256 ? 0 : height, 1); // height
    entry.writeUInt8(0, 2); // color count
    entry.writeUInt8(0, 3); // reserved
    entry.writeUInt16LE(1, 4); // color planes
    entry.writeUInt16LE(32, 6); // bits per pixel
    entry.writeUInt32LE(data.length, 8);
    entry.writeUInt32LE(currentOffset, 12);
    entries.push(entry);
    currentOffset += data.length;
  }

  return Buffer.concat([header, ...entries, ...pngs.map(p => p.data)]);
}

const sizes = [16, 32, 48];
const pngs = sizes.map(s => ({
  width: s,
  height: s,
  data: fs.readFileSync('public/favicon-' + (s === 48 ? '48x48' : s + 'x' + s) + '.png')
}));

// Fix: use proper file names
const pngsFixed = [
  { width: 16, height: 16, data: fs.readFileSync('public/favicon-16x16.png') },
  { width: 32, height: 32, data: fs.readFileSync('public/favicon-32x32.png') },
  { width: 48, height: 48, data: fs.readFileSync('public/favicon-48x48.png') },
];

const ico = buildIco(pngsFixed);
fs.writeFileSync('app/favicon.ico', ico);
console.log('favicon.ico written:', ico.length, 'bytes');
"

